import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):

    def calculate_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    best_node = None
    best_distance = float('inf')

    for i, truck_pos in enumerate(all_truck_pos):
        for j, customer_pos in enumerate(unvisited_customers):
            distance_to_customer = calculate_distance(truck_pos, customer_pos)
            distance_to_depot = calculate_distance(customer_pos, depot_pos)
            total_distance = distance_to_customer + distance_to_depot

            if total_distance < best_distance:
                best_distance = total_distance
                best_node = j

    return best_node
